import{_ as s,o as i,c as e,ag as n}from"./chunks/framework.BVZs_YW1.js";const k=JSON.parse('{"title":"Linux 下鼠标指针主题与大小设置","description":"","frontmatter":{},"headers":[],"relativePath":"notes/desktop/cursor.md","filePath":"notes/desktop/cursor.md"}'),t={name:"notes/desktop/cursor.md"};function l(p,a,h,o,d,r){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="linux-下鼠标指针主题与大小设置" tabindex="-1">Linux 下鼠标指针主题与大小设置 <a class="header-anchor" href="#linux-下鼠标指针主题与大小设置" aria-label="Permalink to &quot;Linux 下鼠标指针主题与大小设置&quot;">​</a></h1><p>鼠标指针在 Linux 上一直不是“一处修改，到处生效”的东西。不同桌面、不同协议、不同工具链，经常各走各的。</p><p>本文分两类：</p><ol><li>你已有 Linux 光标主题，只想切换主题/调整大小。</li><li>你拿到的是 Windows <code>.ani/.cur</code> 主题，先转换成 Linux 可用格式再启用。</li></ol><h2 id="只改已有主题-不转换" tabindex="-1">只改已有主题（不转换） <a class="header-anchor" href="#只改已有主题-不转换" aria-label="Permalink to &quot;只改已有主题（不转换）&quot;">​</a></h2><h3 id="gnome-gtk" tabindex="-1">GNOME / GTK <a class="header-anchor" href="#gnome-gtk" aria-label="Permalink to &quot;GNOME / GTK&quot;">​</a></h3><p>设置主题：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gsettings</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> org.gnome.desktop.interface</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cursor-theme</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ThemeName&#39;</span></span></code></pre></div><p>设置大小：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gsettings</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> org.gnome.desktop.interface</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cursor-size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 24</span></span></code></pre></div><h3 id="kde-plasma" tabindex="-1">KDE Plasma <a class="header-anchor" href="#kde-plasma" aria-label="Permalink to &quot;KDE Plasma&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">plasma-apply-cursortheme</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ThemeName</span></span></code></pre></div><h3 id="hyprland" tabindex="-1">Hyprland <a class="header-anchor" href="#hyprland" aria-label="Permalink to &quot;Hyprland&quot;">​</a></h3><p>在 <code>~/.config/hypr/hyprland.conf</code>：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">exec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = hyprctl setcursor ThemeName 24</span></span></code></pre></div><h3 id="sway" tabindex="-1">Sway <a class="header-anchor" href="#sway" aria-label="Permalink to &quot;Sway&quot;">​</a></h3><p>在 <code>~/.config/sway/config</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>seat * xcursor_theme ThemeName 24</span></span></code></pre></div><h3 id="niri" tabindex="-1">Niri <a class="header-anchor" href="#niri" aria-label="Permalink to &quot;Niri&quot;">​</a></h3><p>在 <code>~/.config/niri/config.kdl</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cursor {</span></span>
<span class="line"><span>    xcursor-theme &quot;ThemeName&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="x11-传统方式" tabindex="-1">X11 传统方式 <a class="header-anchor" href="#x11-传统方式" aria-label="Permalink to &quot;X11 传统方式&quot;">​</a></h3><p><code>~/.Xresources</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Xcursor.theme: ThemeName</span></span>
<span class="line"><span>Xcursor.size: 24</span></span></code></pre></div><p>然后加载：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xrdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -merge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.Xresources</span></span></code></pre></div><h2 id="把-windows-ani-cur-转成-linux-主题-ani2xcursor" tabindex="-1">把 Windows <code>.ani/.cur</code> 转成 Linux 主题（ani2xcursor） <a class="header-anchor" href="#把-windows-ani-cur-转成-linux-主题-ani2xcursor" aria-label="Permalink to &quot;把 Windows \`.ani/.cur\` 转成 Linux 主题（ani2xcursor）&quot;">​</a></h2><p>项目：<code>ani2xcursor</code>（支持 <code>.ani/.cur</code>，可多尺寸导出，可生成 manifest 修映射）</p><h3 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h3><p>Arch（AUR）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">paru</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ani2xcursor-bin</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yay</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ani2xcursor-bin</span></span></code></pre></div><p>NixOS（直接试跑）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nix</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github:yuzujr/ani2xcursor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/cursor/folder</span></span></code></pre></div><h3 id="基础转换" tabindex="-1">基础转换 <a class="header-anchor" href="#基础转换" aria-label="Permalink to &quot;基础转换&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ani2xcursor</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/cursor/folder</span></span></code></pre></div><p>常用参数：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>--install            安装到 $XDG_DATA_HOME/icons</span></span>
<span class="line"><span>--size 24,32         目标尺寸，不足时自动缩放补齐</span></span>
<span class="line"><span>--list               先看源文件可用尺寸</span></span>
<span class="line"><span>--manifest           生成预览 + manifest.toml 供手工修映射</span></span>
<span class="line"><span>--skip-broken        跳过损坏光标继续处理</span></span></code></pre></div><h3 id="manifest-模式-推荐" tabindex="-1">Manifest 模式（推荐） <a class="header-anchor" href="#manifest-模式-推荐" aria-label="Permalink to &quot;Manifest 模式（推荐）&quot;">​</a></h3><p>先生成模板与预览：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ani2xcursor</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/cursor/folder</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --manifest</span></span></code></pre></div><p>会在输入目录下生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ani2xcursor/</span></span>
<span class="line"><span>├── manifest.toml</span></span>
<span class="line"><span>└── previews/</span></span></code></pre></div><p>编辑 <code>manifest.toml</code> 后再次运行转换命令。若存在 <code>manifest.toml</code>，会优先使用它（并覆盖 <code>--size</code>）。</p><h2 id="解决-系统改了-但部分程序不跟随" tabindex="-1">解决“系统改了，但部分程序不跟随” <a class="header-anchor" href="#解决-系统改了-但部分程序不跟随" aria-label="Permalink to &quot;解决“系统改了，但部分程序不跟随”&quot;">​</a></h2><p>这通常不是改错，而是不同程序读取了不同配置源。</p><h3 id="libxcursor-fallback-很关键" tabindex="-1">libXcursor fallback（很关键） <a class="header-anchor" href="#libxcursor-fallback-很关键" aria-label="Permalink to &quot;libXcursor fallback（很关键）&quot;">​</a></h3><p>有些 X11/XWayland 程序会回退读取名为 <code>default</code> 的主题。建议建一个用户级别 fallback：</p><p><code>~/.icons/default/index.theme</code></p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Icon Theme]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Inherits</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=ThemeName</span></span></code></pre></div><p>系统级可用 <code>/usr/share/icons/default/index.theme</code>。<br><code>Inherits</code> 里只会使用第一个主题名。</p><h3 id="最后一步" tabindex="-1">最后一步 <a class="header-anchor" href="#最后一步" aria-label="Permalink to &quot;最后一步&quot;">​</a></h3><p>修改后建议重新登录图形会话，或至少重启目标程序，避免旧配置缓存。</p>`,52)])])}const u=s(t,[["render",l]]);export{k as __pageData,u as default};
